import React, { createContext, useContext, useEffect, useState } from 'react';
import {
  BrowserRouter as Router,
  Routes,
  Route,
  Link,
  Navigate,
  useNavigate,
  useParams,
} from 'react-router-dom';
import {
  Sun,
  Moon,
  LogIn,
  UserPlus,
  DoorOpen,
  CalendarCheck,
  Home as HomeIcon,
} from 'lucide-react';

/* --------------------------------------------------------------------- */
/* ------------------------------ THEME -------------------------------- */
type Theme = 'light' | 'dark';
const ThemeCtx = createContext<{ theme: Theme; toggle: () => void }>({
  theme: 'dark',
  toggle: () => {},
});
const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({
  children,
}) => {
  const [theme, setTheme] = useState<Theme>(
    (localStorage.getItem('theme') as Theme) || 'dark'
  );
  const toggle = () =>
    setTheme(prev => {
      const nxt = prev === 'dark' ? 'light' : 'dark';
      localStorage.setItem('theme', nxt);
      return nxt;
    });
  useEffect(() => {
    document.documentElement.classList.toggle('dark', theme === 'dark');
  }, [theme]);
  return (
    <ThemeCtx.Provider value={{ theme, toggle }}>{children}</ThemeCtx.Provider>
  );
};
const useTheme = () => useContext(ThemeCtx);

/* --------------------------------------------------------------------- */
/* ------------------------------- AUTH -------------------------------- */
type User = { username: string; reservations: number[] };
interface AuthContextVal {
  user: User | null;
  login: (u: string, p: string) => void;
  register: (u: string, p: string) => void;
  logout: () => void;
  reserve: (roomId: number) => void;
}
const AuthCtx = createContext<AuthContextVal>({} as AuthContextVal);

const AuthProvider: React.FC<{ children: React.ReactNode }> = ({
  children,
}) => {
  const [user, setUser] = useState<User | null>(() => {
    const stored = localStorage.getItem('user');
    return stored ? (JSON.parse(stored) as User) : null;
  });

  const sync = (u: User | null) => {
    setUser(u);
    localStorage.setItem('user', u ? JSON.stringify(u) : '');
  };

  const login = (username: string) =>
    sync({ username, reservations: user?.reservations || [] });

  const register = (username: string) =>
    sync({ username, reservations: [] });

  const logout = () => sync(null);

  const reserve = (roomId: number) => {
    if (!user) return;
    if (!user.reservations.includes(roomId)) {
      sync({ ...user, reservations: [...user.reservations, roomId] });
    }
  };

  return (
    <AuthCtx.Provider value={{ user, login, register, logout, reserve }}>
      {children}
    </AuthCtx.Provider>
  );
};
const useAuth = () => useContext(AuthCtx);

/* --------------------------------------------------------------------- */
