/* --------------------------- PAGES ----------------------------------- */
const HomePage: React.FC = () => (
  <main className="mx-auto max-w-6xl px-4 py-10">
    <h1 className="mb-6 text-3xl font-bold">Explora alojamientos</h1>
    <div className="grid gap-6 sm:grid-cols-2 md:grid-cols-3">
      {ROOMS.map(r => (
        <RoomCard key={r.id} room={r} />
      ))}
    </div>
  </main>
);

const RoomDetailPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const room = ROOMS.find(r => r.id === Number(id));
  const { user, reserve } = useAuth();
  if (!room) return <Navigate to="/" />;
  return (
    <main className="mx-auto max-w-4xl px-4 py-10">
      <img
        src={room.image}
        alt={room.title}
        className="mb-6 h-72 w-full rounded-lg object-cover"
      />
      <h2 className="text-2xl font-bold">{room.title}</h2>
      <p className="text-sm text-zinc-400">{room.location}</p>
      <p className="mt-4">{room.description}</p>
      <div className="mt-6 flex items-center justify-between">
        <span className="text-xl font-semibold">${room.price} / noche</span>
        {user ? (
          <button
            onClick={() => reserve(room.id)}
            className="flex items-center gap-2 rounded bg-cyan-500 px-4 py-2 font-semibold text-zinc-900 hover:bg-cyan-400"
          >
            <CalendarCheck className="h-5 w-5" /> Reservar
          </button>
        ) : (
          <Link
            to="/login"
            className="rounded bg-cyan-500 px-4 py-2 font-semibold text-zinc-900 hover:bg-cyan-400"
          >
            Inicia sesión para reservar
