const ReservationsPage: React.FC = () => {
  const { user } = useAuth();
  if (!user) return <Navigate to="/login" />;
  const rooms = ROOMS.filter(r => user.reservations.includes(r.id));
  return (
    <main className="mx-auto max-w-4xl px-4 py-10">
      <h1 className="mb-6 text-3xl font-bold">Mis reservas</h1>
      {rooms.length === 0 ? (
        <p className="text-zinc-400">Aún no tienes reservas.</p>
      ) : (
        <div className="grid gap-6 sm:grid-cols-2">
          {rooms.map(r => (
            <div
              key={r.id}
              className="overflow-hidden rounded-lg border border-zinc-800"
            >
              <img
                src={r.image}
                alt={r.title}
                className="h-40 w-full object-cover"
              />
              <div className="p-4">
                <h3 className="text-lg font-semibold">{r.title}</h3>
                <p className="text-sm text-zinc-400">{r.location}</p>
              </div>
            </div>
          ))}
        </div>
      )}
