  );
};

/* ---------------------- AUTH FORMS ----------------------------------- */
const AuthPage: React.FC<{
  mode: 'login' | 'register';
}> = ({ mode }) => {
  const isLogin = mode === 'login';
  const { login, register, user } = useAuth();
  const navigate = useNavigate();
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  useEffect(() => {
    if (user) navigate('/');
  }, [user, navigate]);

  const submit = (e: React.FormEvent) => {
    e.preventDefault();
    isLogin ? login(username, password) : register(username, password);
    navigate('/');
  };
  return (
    <main className="mx-auto flex min-h-[60vh] max-w-md flex-col justify-center px-4">
      <form
        onSubmit={submit}
        className="rounded-lg border border-zinc-800 bg-zinc-800 p-8 shadow-lg"
      >
        <h2 className="mb-6 text-center text-2xl font-bold">
          {isLogin ? 'Iniciar sesión' : 'Crear cuenta'}
        </h2>
        <div className="mb-4">
          <label className="mb-1 block text-sm">Usuario</label>
          <input
            required
            className="w-full rounded bg-zinc-900 p-2 text-sm outline-none focus:ring-2 focus:ring-cyan-500"
            value={username}
            onChange={e => setUsername(e.target.value)}
          />
        </div>
        <div className="mb-6">
          <label className="mb-1 block text-sm">Contraseña</label>
          <input
            required
            type="password"
            className="w-full rounded bg-zinc-900 p-2 text-sm outline-none focus:ring-2 focus:ring-cyan-500"
            value={password}
            onChange={e => setPassword(e.target.value)}
          />
        </div>
        <button
          type="submit"
          className="w-full rounded bg-cyan-500 py-2 font-semibold text-zinc-900 hover:bg-cyan-400"
        >
          {isLogin ? 'Entrar' : 'Registrarme'}
        </button>
        <p className="mt-4 text-center text-xs text-zinc-400">
          {isLogin ? '¿No tienes cuenta?' : '¿Ya tienes cuenta?'}{' '}
          <Link
            to={isLogin ? '/register' : '/login'}
            className="text-cyan-400 hover:underline"
          >
            {isLogin ? 'Regístrate' : 'Inicia sesión'}
          </Link>
        </p>
      </form>
    </main>
  );
};

